nw_f32 = np.array([bf16_to_f32(int(v)) for v in nw_raw.flatten()], dtype=np.float32)

hidden = rust_hidden
residual = hidden.copy()

# Step 1: Norm
normed = rms_norm_cpu(hidden, nw_f32, eps)
print(f"Step 1 - normed: RMS={np.sqrt(np.mean(normed**2)):.6f}, first5={normed[:5]}")
print(f"  Rust:    RMS=1.021826, first5=[-0.69211709,0.65284806,0.98663509,2.11316609,-0.63812214]")
normed_diff = np.max(np.abs(normed[:5] - np.array([-0.69211709,0.65284806,0.98663509,2.11316609,-0.63812214])))
print(f"  max_diff(first5)={normed_diff:.8f}")

# Step 2: Projections
qkv = dequant_matvec_4bit(weights["in_proj_qkv.weight"], weights["in_proj_qkv.scales"], weights["in_proj_qkv.biases"], normed, group_size)
z = dequant_matvec_4bit(weights["in_proj_z.weight"], weights["in_proj_z.scales"], weights["in_proj_z.biases"], normed, group_size)
beta = dequant_matvec_4bit(weights["in_proj_b.weight"], weights["in_proj_b.scales"], weights["in_proj_b.biases"], normed, group_size)
alpha = dequant_matvec_4bit(weights["in_proj_a.weight"], weights["in_proj_a.scales"], weights["in_proj_a.biases"], normed, group_size)

print(f"Step 2 - qkv: RMS={np.sqrt(np.mean(qkv**2)):.6f}, first5={qkv[:5]}")
print(f"  Rust: RMS=1.233854, first5=[-1.66225898,1.38664961,0.78253686,-0.64751947,-0.09329744]")
qkv_diff = np.max(np.abs(qkv[:5] - np.array([-1.66225898,1.38664961,0.78253686,-0.64751947,-0.09329744])))
print(f"  max_diff(first5)={qkv_diff:.8f}")

print(f"  z: RMS={np.sqrt(np.mean(z**2)):.6f}, first5={z[:5]}")
print(f"    Rust: RMS=1.180306, first5=[-0.81855994,-0.96266544,0.12770036,0.34419328,0.98371059]")
z_diff = np.max(np.abs(z[:5] - np.array([-0.81855994,-0.96266544,0.12770036,0.34419328,0.98371059])))
print(f"    max_diff(first5)={z_diff:.8f}")

# Step 3: Conv1d
conv_state = np.zeros(3 * qkv_dim, dtype=np.float32)
conv_out = cpu_conv1d_step(conv_state, qkv, weights["conv1d.weight"], 4)
lin_q = conv_out[:total_key]
lin_k = conv_out[total_key:2*total_key]
lin_v = conv_out[2*total_key:]

print(f"Step 3 - conv_out: RMS={np.sqrt(np.mean(conv_out**2)):.6f}, first5={conv_out[:5]}")
print(f"  Rust: RMS=0.141741, first5=[0.00273407,-0.04130160,0.00071994,-0.02012886,-0.00252193]")
print(f"  lin_q: RMS={np.sqrt(np.mean(lin_q**2)):.6f}, lin_k: RMS={np.sqrt(np.mean(lin_k**2)):.6f}, lin_v: RMS={np.sqrt(np.mean(lin_v**2)):.6f}")
print(f"  Rust: lin_q_rms=0.053235, lin_k_rms=0.025515, lin_v_rms=0.196058")

# Step 4: Q/K RMS norm
q_normed = np.zeros(total_key, dtype=np.float32)
k_normed = np.zeros(total_key, dtype=np.float32)
for h in range(num_k_heads):
    qh = lin_q[h * key_dim:(h + 1) * key_dim]
    qh_out = rms_norm_bare_cpu(qh, 1e-6)
    q_normed[h * key_dim:(h + 1) * key_dim] = qh_out * (inv_scale * inv_scale)
for h in range(num_k_heads):
    kh = lin_k[h * key_dim:(h + 1) * key_dim]
    kh_out = rms_norm_bare_cpu(kh, 1e-6)
    k_normed[h * key_dim:(h + 1) * key_dim] = kh_out * inv_scale

print(f"Step 4 - q_normed: RMS={np.sqrt(np.mean(q_normed**2)):.6f}, first5={q_normed[:5]}")
print(f"  Rust: RMS=0.007811, first5=[0.00022240,-0.00335957,0.00005856,-0.00163733,-0.00020514]")
print(f"  k_normed: RMS={np.sqrt(np.mean(k_normed**2)):.6f}, first5={k_normed[:5]}")
print(f"  Rust: RMS=0.087580, first5=[-0.00627787,-0.01265508,0.00935181,-0.02377506,-0.02896323]")

# Step 5: SSM
a_log_raw = weights.get("A_log")
dt_bias_raw = weights.get("dt_bias")
a_log = a_log_raw.flatten().astype(np.float32) if a_log_raw is not None else None
dt_bias = np.array([bf16_to_f32(int(v)) for v in dt_bias_raw.flatten()], dtype=np.float32) if dt_bias_raw is not None else None

ssm_state = np.zeros(num_v_heads * value_dim * key_dim, dtype=np.float32)
out_values = np.zeros(total_value, dtype=np.float32)

for vh in range(num_v_heads):
    kh = vh // k_heads_per_v
    a_val = 1.0 if a_log is None else float(a_log[vh])
    dt_b = 0.0 if dt_bias is None else float(dt_bias[vh])
    softplus_val = np.log(1.0 + np.exp(float(alpha[vh]) + dt_b))
    g_decay = np.exp(-np.exp(a_val) * softplus_val)
    beta_gate = cpu_sigmoid(float(beta[vh]))

    s_off = vh * value_dim * key_dim
    ssm = ssm_state[s_off:s_off + value_dim * key_dim].reshape(value_dim, key_dim)
    v_h = lin_v[vh * value_dim:(vh + 1) * value_dim]
    k_h = k_normed[kh * key_dim:(kh + 1) * key_dim]

    # Decay
    ssm *= g_decay
    # kv_mem + delta
    kv_mem = ssm @ k_h
    delta = (v_h - kv_mem) * beta_gate
    ssm += np.outer(delta, k_h)
    # Output
    q_h = q_normed[kh * key_dim:(kh + 1) * key_dim]
    out_values[vh * value_dim:(vh + 1) * value_dim] = ssm @ q_h

print(f"Step 5 - ssm_out: RMS={np.sqrt(np.mean(out_values**2)):.6f}, first5={out_values[:5]}")
print(f"  Rust: RMS=0.001013, first5=[0.00000084,0.00001160,-0.00000473,-0.00002311,0.00000307]")

# Step 6: Gated norm
gnw_raw = weights.get("norm.weight")
gated_out = np.zeros(total_value, dtype=np.float32)
if gnw_raw is not None:
    gnw_f32 = np.array([bf16_to_f32(int(v)) for v in gnw_raw.flatten()], dtype=np.float32)
    for vh in range(num_v_heads):
        oh = out_values[vh * value_dim:(vh + 1) * value_dim]
        zh = z[vh * value_dim:(vh + 1) * value_dim]
        gh = np.zeros(value_dim, dtype=np.float32)
        sum_sq = np.sum(oh * oh)
        inv_rms = 1.0 / np.sqrt(sum_sq / value_dim + eps)
        for i in range(value_dim):
            w = gnw_f32[i]
            silu_z = zh[i] / (1.0 + np.exp(-zh[i]))
            gh[i] = oh[i] * inv_rms * w * silu_z
        gated_out[vh * value_dim:(vh + 1) * value_dim] = gh
else:
    gated_out = out_values.copy()

print(f"Step 6 - gated_out: RMS={np.sqrt(np.mean(gated_out**2)):.6f}, first5={gated_out[:5]}")
print(f"  Rust: RMS=0.051390, first5=[-0.00017948,-0.00261693,-0.00027732,-0.00410819,0.00197583]")

# Step 7: Output projection
attn_out = dequant_matvec_4bit(weights["out_proj.weight"], weights["out_proj.scales"], weights["out_proj.biases"], gated_out, group_size)

print(f"Step 7 - attn_out: RMS={np.sqrt(np.mean(attn_out**2)):.6f}, first5={attn_out[:5]}")
print(f"  Rust: RMS=0.048375, first5=[-0.04185568,0.02973542,-0.02187887,-0.03630564,-0.00085997]")

# Step 8: Residual
hidden_out = residual + attn_out
print(f"Step 8 - hidden_out: RMS={np.sqrt(np.mean(hidden_out**2)):.6f}, first5={hidden_out[:5]}")
print(f"  Rust: RMS=0.050581, first5=[-0.04979025,0.03766999,-0.00997701,-0.00853464,-0.00879454]")

# Overall comparison
print("\n=== COMPARISON ===")
max_diffs = {
    "normed": np.max(np.abs(normed - np.array([-0.69211709,0.65284806,0.98663509,2.11316609,-0.63812214]))),
    "qkv": np.max(np.abs(qkv[:5] - np.array([-1.66225898,1.38664961,0.78253686,-0.64751947,-0.09329744]))),
    "z": np.max(np.abs(z[:5] - np.array([-0.81855994,-0.96266544,0.12770036,0.34419328,0.98371059]))),
    "lin_q": np.max(np.abs(lin_q[:5] - np.array([0.00017669, 0.02990557, -0.00029319, 0.02619898, 0.00094156]))),
}
for k, v in max_diffs.items():
    print(f"  {k}: max_diff(first5)={v:.8f}")

# Most importantly, check if Python output matches Rust output
print(f"\nFinal hidden_out comparison:")
print(f"  Py RMS: {np.sqrt(np.mean(hidden_out**2)):.6f}")
print(f"  Rust RMS: 0.050581")
print(f"  Py first5: {hidden_out[:5]}")
print(f"  Rust first5: [-0.04979025, 0.03766999, -0.00997701, -0.00853464, -0.00879454]")
print(f"  Max diff (first 5): {np.max(np.abs(hidden_out[:5] - np.array([-0.04979025, 0.03766999, -0.00997701, -0.00853464, -0.00879454]))):.8f}")
print(f"  Max diff (all): {np.max(np.abs(hidden_out - np.array([float(x) for x in '-0.04979025,0.03766999,-0.00997701,-0.00853464,-0.00879454'.split(',')]))):.8f}")
